import { reactive, ref } from 'vue'

import type { ColorModeInstance } from './types'
import { defineNuxtPlugin, useHead, useState, useRouter, useCookie } from '#imports'
import { preference, dataValue, storage, storageKey } from '#build/color-mode-options.mjs'

export default defineNuxtPlugin((nuxtApp) => {
  const colorMode = nuxtApp.ssrContext?.islandContext
    ? ref<Partial<ColorModeInstance>>({}).value
    : useState<ColorModeInstance>('color-mode', () => reactive({
      preference,
      value: preference,
      unknown: true,
      forced: false,
    })).value

  const htmlAttrs: Record<string, string> = {}

  if (storage === 'cookie') {
    const cookie = useCookie(storageKey)
    if (cookie.value) {
      colorMode.preference = cookie.value
    }
  }
  useHead({ htmlAttrs })

  useRouter().afterEach((to) => {
    const forcedColorMode = to.meta.colorMode

    if (forcedColorMode && forcedColorMode !== 'system') {
      htmlAttrs['data-color-mode-forced'] = forcedColorMode
      // @ts-expect-error readonly property
      colorMode.value = forcedColorMode
      if (dataValue) {
        htmlAttrs[`data-${dataValue}`] = colorMode.value
      }
      colorMode.forced = true
    }
    else if (forcedColorMode === 'system') {
      console.warn('You cannot force the colorMode to system at the page level.')
    }
  })

  nuxtApp.provide('colorMode', colorMode)
})

import { fileURLToPath } from 'node:url'
import { addComponentsDir, addImportsDir, createResolver, defineNuxtModule, installModule } from '@nuxt/kit'
import defu from 'defu'
import { extendUnocssOptions } from './unocss'

export { unocssPreset } from './unocss'

function rPath(p: string) {
  return fileURLToPath(new URL(p, import.meta.url).toString())
}

export interface ModuleOptions {
  dev?: boolean
  preset?: string
}

export default defineNuxtModule<ModuleOptions>({
  meta: {
    name: '@nuxt/devtools-ui-kit',
    configKey: 'devtoolsUIKit',
  },
  defaults: {
    preset: rPath('./preset'),
    dev: false,
  },
  async setup(options, nuxt) {
    // composables
    addImportsDir(rPath('./composables'))

    // Standard components
    addComponentsDir({ path: rPath('./components') })

    nuxt.options.css.unshift(rPath('assets/styles.css'))

    if (!options.dev)
      nuxt.options.unocss = extendUnocssOptions(nuxt.options.unocss || {})

    // eslint-disable-next-line ts/ban-ts-comment
    // @ts-ignore - module options
    nuxt.options.colorMode = defu(nuxt.options.colorMode, { classSuffix: '' })

    const resolver = createResolver(import.meta.url)
    await installModule(await resolver.resolvePath('@unocss/nuxt'))
    await installModule(await resolver.resolvePath('@vueuse/nuxt'))
    await installModule(await resolver.resolvePath('v-lazy-show/nuxt'))
  },
})

import { db, schema } from 'hub:db'
import { and, eq } from 'drizzle-orm'
import { z } from 'zod'

export default defineEventHandler(async (event) => {
  const session = await getUserSession(event)

  const { id } = await getValidatedRouterParams(event, z.object({
    id: z.string()
  }).parse)

  const { messageId, isUpvoted } = await readValidatedBody(event, z.object({
    messageId: z.string(),
    isUpvoted: z.boolean().optional()
  }).parse)

  const chat = await db.query.chats.findFirst({
    where: () => and(
      eq(schema.chats.id, id as string),
      eq(schema.chats.userId, session.user?.id || session.id)
    )
  })

  if (!chat) {
    throw createError({ statusCode: 404, statusMessage: 'Chat not found' })
  }

  const message = await db.query.messages.findFirst({
    where: () => and(
      eq(schema.messages.id, messageId),
      eq(schema.messages.chatId, id as string)
    )
  })

  if (!message) {
    throw createError({ statusCode: 404, statusMessage: 'Message not found' })
  }

  if (message.role !== 'assistant') {
    throw createError({ statusCode: 400, statusMessage: 'Can only vote on assistant messages' })
  }

  if (isUpvoted === undefined) {
    await db.delete(schema.votes).where(
      and(
        eq(schema.votes.chatId, id as string),
        eq(schema.votes.messageId, messageId)
      )
    )
  } else {
    await db.insert(schema.votes).values({
      chatId: id as string,
      messageId,
      isUpvoted
    }).onConflictDoUpdate({
      target: [schema.votes.chatId, schema.votes.messageId],
      set: { isUpvoted }
    })
  }

  return { chatId: id, messageId, isUpvoted }
})

import { stringifyQuery } from 'ufo'
import type { NitroConfig } from 'nitropack'
import { defineProvider } from '../utils/provider'

// https://vercel.com/docs/build-output-api/v3/configuration#images

interface VercelOptions {
  baseURL?: string
  formats?: NonNullable<NonNullable<NonNullable<NitroConfig['vercel']>['config']>['images']>['formats']
  modifiers?: {
    quality?: string | number
  }
}

export default defineProvider<VercelOptions>({
  validateDomains: true,
  getImage: (src, { modifiers, baseURL = '/_vercel/image' }, ctx) => {
    const validWidths = Object.values(ctx.options.screens || {}).sort((a, b) => a - b)
    const largestWidth = validWidths[validWidths.length - 1] || 0
    let width = Number(modifiers?.width || 0)

    if (!width) {
      width = largestWidth
      if (import.meta.dev) {
        console.warn(`A defined width should be provided to use the \`vercel\` provider. Defaulting to \`${largestWidth}\`. Warning originated from \`${src}\`.`)
      }
    }
    else if (!validWidths.includes(width)) {
      width = validWidths.find(validWidth => validWidth > width) || largestWidth
      if (import.meta.dev) {
        console.warn(`The width being used (\`${modifiers?.width}\`) should be added to \`image.screens\`. Defaulting to \`${width}\`. Warning originated from \`${src}\`.`)
      }
    }

    if (import.meta.dev) {
      return { url: src }
    }

    return {
      url: baseURL + '?' + stringifyQuery({
        url: src,
        w: String(width),
        q: String(modifiers?.quality || '100'),
      }),
    }
  },
})

import { encodeQueryItem, hasProtocol, joinURL } from 'ufo'
import { createOperationsGenerator } from '../utils/index'
import { defineProvider } from '../utils/provider'

const operationsGenerator = createOperationsGenerator({
  keyMap: {
    width: 'w',
    height: 'h',
    dpr: 'dpr',
    fit: 'fit',
    gravity: 'g',
    quality: 'q',
    format: 'f',
    sharpen: 'sharpen',
  },
  valueMap: {
    fit: {
      cover: 'cover',
      contain: 'contain',
      fill: 'scale-down',
      outside: 'crop',
      inside: 'pad',
    },
    gravity: {
      auto: 'auto',
      side: 'side',
    },
  },
  joinWith: ',',
  formatter: (key, value) => encodeQueryItem(key, value),
})

const defaultModifiers = {}

interface CloudflareOptions {
  baseURL?: string
}

// https://developers.cloudflare.com/images/image-resizing/url-format/
export default defineProvider<CloudflareOptions>({
  getImage: (src, {
    modifiers,
    baseURL = '/',
  }) => {
    const mergeModifiers = { ...defaultModifiers, ...modifiers }
    const operations = operationsGenerator(mergeModifiers as any)

    // https://<ZONE>/cdn-cgi/image/<OPTIONS>/<SOURCE-IMAGE>
    const url = operations ? joinURL(baseURL, 'cdn-cgi/image', operations, src) : hasProtocol(src) ? src : joinURL(baseURL, src)

    return {
      url,
    }
  },
})

import { resolvePackageJSON } from 'pkg-types'
import { useNuxt } from '@nuxt/kit'
import { isCI, provider } from 'std-env'
import { logger } from '../utils.ts'

const installPrompts = new Set<string>()

export async function installNuxtModule (name: string, options?: { rootDir?: string, searchPaths?: string[], prompt?: boolean }) {
  if (installPrompts.has(name)) { return }
  installPrompts.add(name)

  const nuxt = useNuxt()
  const rootDir = options?.rootDir || nuxt.options.rootDir
  const searchPaths = options?.searchPaths || nuxt.options.modulesDir

  for (const parent of searchPaths) {
    if (await resolvePackageJSON(name, { parent }).catch(() => null)) {
      return true
    }
  }

  logger.info(`Package ${name} is missing`)

  if (isCI) {
    return false
  }

  if (options?.prompt === true || (options?.prompt !== false && provider !== 'stackblitz')) {
    const confirm = await logger.prompt(`Do you want to install ${name} package?`, {
      type: 'confirm',
      name: 'confirm',
      initial: true,
    })

    if (confirm !== true) {
      return false
    }
  }

  logger.info(`Installing ${name}...`)
  try {
    const { runCommand } = await import('@nuxt/cli')
    await runCommand('module', ['add', name, '--cwd', rootDir])
    logger.success(`Installed ${name}`)
    return true
  } catch (err) {
    logger.error(err)
    return false
  }
}

import process from 'node:process'

import { defineCommand } from 'citty'
import { colors } from 'consola/utils'
import { resolve } from 'pathe'

import { clearBuildDir } from '../utils/fs'
import { loadKit } from '../utils/kit'
import { logger } from '../utils/logger'
import { relativeToProcess } from '../utils/paths'
import { cwdArgs, dotEnvArgs, envNameArgs, extendsArgs, legacyRootDirArgs, logLevelArgs } from './_shared'

export default defineCommand({
  meta: {
    name: 'prepare',
    description: 'Prepare Nuxt for development/build',
  },
  args: {
    ...dotEnvArgs,
    ...cwdArgs,
    ...logLevelArgs,
    ...envNameArgs,
    ...extendsArgs,
    ...legacyRootDirArgs,
  },
  async run(ctx) {
    process.env.NODE_ENV = process.env.NODE_ENV || 'production'

    const cwd = resolve(ctx.args.cwd || ctx.args.rootDir)

    const { loadNuxt, buildNuxt, writeTypes } = await loadKit(cwd)
    const nuxt = await loadNuxt({
      cwd,
      dotenv: {
        cwd,
        fileName: ctx.args.dotenv,
      },
      envName: ctx.args.envName, // c12 will fall back to NODE_ENV
      overrides: {
        _prepare: true,
        logLevel: ctx.args.logLevel as 'silent' | 'info' | 'verbose',
        ...(ctx.args.extends && { extends: ctx.args.extends }),
        ...ctx.data?.overrides,
      },
    })
    await clearBuildDir(nuxt.options.buildDir)

    await buildNuxt(nuxt)
    await writeTypes(nuxt)
    logger.success(`Types generated in ${colors.cyan(relativeToProcess(nuxt.options.buildDir))}.`)
  },
})

import type { MdcConfig, ModuleOptions as MDCModuleOptions } from '@nuxtjs/mdc'
import type { Nuxt } from '@nuxt/schema'
import { extendViteConfig } from '@nuxt/kit'
import { createJiti } from 'jiti'
import type { ModuleOptions } from '../types'
import { setMdcConfigResolver } from './content'

export async function configureMDCModule(contentOptions: ModuleOptions, nuxt: Nuxt) {
  const mdcOptions = (nuxt.options as unknown as { mdc: MDCModuleOptions }).mdc
  contentOptions.renderer.alias = {
    ...(mdcOptions?.components?.map || {}),
    ...(contentOptions.renderer.alias || {}),
  }

  // Provide a lazy resolver for mdc configs. When the highlighter needs
  // configs it fires mdc:configSources to collect paths from all modules
  // (including file-based configs registered by @nuxtjs/mdc), then imports
  // them. This avoids any dependency on modules:done hook ordering.
  let _configs: MdcConfig[] | undefined
  setMdcConfigResolver(async () => {
    if (!_configs) {
      const paths: string[] = []
      await nuxt.callHook('mdc:configSources', paths)
      const jiti = createJiti(nuxt.options.rootDir)
      _configs = paths.length
        ? await Promise.all(paths.map(path => jiti.import(path).then(m => (m as { default: MdcConfig }).default || m)))
        : []
    }
    return _configs
  })

  // Update mdc optimizeDeps options
  extendViteConfig((config) => {
    config.optimizeDeps ||= {}
    config.optimizeDeps.include ||= []
    config.optimizeDeps.include.push('@nuxt/content > slugify')
    config.optimizeDeps.include = config.optimizeDeps.include
      .map(id => id.replace(/^@nuxtjs\/mdc > /, '@nuxt/content > @nuxtjs/mdc > '))
  })
}

import { useClipboard } from '@vueuse/core'
import { useRouter } from '#app/composables/router'
import { devtoolsUiShowNotification } from '#imports'
import { rpc } from './rpc'
import { useServerConfig, useVirtualFiles } from './state'
import { useCurrentVirtualFile } from './state-routes'
import { telemetry } from './telemetry'

const COLON_SEPARATOR_RE = /:/g

export function useOpenInEditor() {
  const config = useServerConfig()
  const virtualFiles = useVirtualFiles()
  const router = useRouter()
  const virtualFileId = useCurrentVirtualFile()

  return async (filepath?: string) => {
    if (!filepath)
      return

    const buildDir = config.value?.buildDir
    const path = (buildDir && filepath.startsWith(buildDir))
      ? `#build${filepath.slice(buildDir.length)}`
      : filepath

    const [realpath, _line = 1, _col = 0] = path.split(COLON_SEPARATOR_RE)

    const vfs = virtualFiles.value?.entries.find(i => i.path === realpath || i.id === realpath)
      || virtualFiles.value?.entries.find(i => i.path === filepath || i.id === filepath)
    if (vfs) {
      // TODO: support line and col
      virtualFileId.value = vfs.id
      router.push('/modules/virtual-files')
    }
    else {
      await rpc.openInEditor(filepath)
    }
  }
}

export function useCopy() {
  const clipboard = useClipboard()

  return (text: string, type?: string) => {
    clipboard.copy(text)

    telemetry('copy', {
      copyType: type,
    })

    devtoolsUiShowNotification({
      message: 'Copied to clipboard',
      icon: 'carbon-checkmark',
    })
  }
}

import type { ContentNavigationItem } from '@nuxt/content'

function getFirstPagePath(item: ContentNavigationItem): string {
  let current = item
  while (current.children?.length) {
    current = current.children[0]!
  }
  return current.path
}

export function useSubNavigation(providedNavigation?: Ref<ContentNavigationItem[] | null | undefined>) {
  const route = useRoute()
  const appConfig = useAppConfig()
  const navigation = providedNavigation ?? inject<Ref<ContentNavigationItem[]>>('navigation')

  const isDocsPage = computed(() => route.meta.layout === 'docs')

  const subNavigationMode = computed(() => {
    if (!isDocsPage.value) return undefined
    return (appConfig.navigation as { sub?: 'header' | 'aside' } | undefined)?.sub
  })

  const currentSection = computed(() => {
    if (!subNavigationMode.value || !navigation?.value) return undefined
    return navigation.value.find(item =>
      route.path === item.path || route.path.startsWith(item.path + '/'),
    )
  })

  const sections = computed(() => {
    if (!subNavigationMode.value || !navigation?.value) return []
    return navigation.value
      .filter(item => item.children?.length)
      .map(item => ({
        label: item.title,
        icon: item.icon as string | undefined,
        to: getFirstPagePath(item),
        active: route.path === item.path || route.path.startsWith(item.path + '/'),
      }))
  })

  const sidebarNavigation = computed(() => {
    if (subNavigationMode.value && currentSection.value) {
      return currentSection.value.children || []
    }
    return navigation?.value || []
  })

  return {
    subNavigationMode,
    sections,
    currentSection,
    sidebarNavigation,
  }
}

import "#nitro/virtual/polyfills";
import type { NodeServerRequest, NodeServerResponse } from "srvx";
import type { ServerResponse, IncomingMessage } from "node:http";
import { toNodeHandler } from "srvx/node";
import wsAdapter from "crossws/adapters/vercel";
import { useNitroApp, getRouteRules } from "nitro/app";
import { resolveWebsocketHooks } from "#nitro/runtime/app";
import { isrRouteRewrite } from "./isr.ts";

const nitroApp = useNitroApp();

const handler = toNodeHandler(nitroApp.fetch);

const ws = import.meta._websocket ? wsAdapter({ resolve: resolveWebsocketHooks }) : undefined;

export default async function nodeHandler(req: NodeServerRequest, res: NodeServerResponse) {
  // https://vercel.com/docs/headers/request-headers#x-forwarded-for
  // srvx node adapter uses req.socket.remoteAddress for req.ip
  let ip: string | undefined;
  Object.defineProperty(req.socket, "remoteAddress", {
    get() {
      const h = req.headers["x-forwarded-for"] as string;
      return (ip ??= h?.split?.(",").shift()?.trim());
    },
  });

  // ISR route rewrite
  const isrURL = isrRouteRewrite(req.url!, req.headers["x-now-route-matches"] as string);
  if (isrURL) {
    const { routeRules } = getRouteRules("", isrURL[0]);
    if (routeRules?.isr) {
      req.url = isrURL[0] + (isrURL[1] ? `?${isrURL[1]}` : "");
    }
  }

  // Websocket upgrade
  // https://crossws.unjs.io/adapters/vercel
  if (ws && (await ws.handleNodeUpgrade(req as IncomingMessage, res as ServerResponse))) {
    return;
  }

  return handler(req as any, res as any);
}

import type { PackageUpdateInfo } from '../types'
import { createRequire } from 'node:module'
import { logger, useNuxt } from '@nuxt/kit'
import { getPackageInfo } from 'local-pkg'
import { fetch } from 'ofetch'
import { readPackageJSON } from 'pkg-types'
import semver from 'semver'

export async function getMainPackageJSON(nuxt = useNuxt()) {
  return readPackageJSON(nuxt.options.rootDir)
}

export async function checkForUpdateOf(name: string, current?: string, nuxt = useNuxt()): Promise<PackageUpdateInfo | undefined> {
  try {
    if (!current) {
      const require = createRequire(nuxt.options.rootDir)
      const modulePaths = [
        ...nuxt.options.modulesDir,
        ...require.resolve.paths(name) || [],
      ]
      const info = await getPackageInfo(name, { paths: modulePaths })
      if (!info)
        return
      current = info.packageJson.version
    }

    if (!current)
      return

    const { getLatestVersion } = await import('fast-npm-meta')
    const { version: latest } = await getLatestVersion(name, {
      fetch,
    })

    const needsUpdate = !!latest && latest !== current && semver.lt(current, latest)

    return {
      name,
      current,
      latest: latest || current,
      needsUpdate,
    }
  }
  catch (e) {
    logger.warn(`Failed to check for update of ${name}:`)
    logger.warn(e)
  }
}

export interface Notification {
  show: boolean
  type: 'info' | 'error' | 'success' | 'warning'
  text: string
  time: Date
  id: number
}

export const useNotificationStore = defineStore('notification', {
  state: () => {
    const notifications: Notification[] = []
    return {
      notifications,
      notificationCount: 0,
    }
  },
  actions: {
    addNotification(text: string, type: Notification['type'] = 'info') {
      this.notifications.push({
        id: this.notificationCount++,
        text,
        type,
        time: new Date(),
        show: true,
      })
    },
    delNotification(id: number) {
      const index = this.notifications.findIndex((m) => m.id === id)
      if (index !== -1) {
        this.notifications.splice(index, 1)
      }
    },
  },
})

export const Notify = {
  info: (text: string) => useNotificationStore().addNotification(text, 'info'),
  success: (text: string) =>
    useNotificationStore().addNotification(text, 'success'),
  warning: (text: string) =>
    useNotificationStore().addNotification(text, 'warning'),
  error: (val: unknown) => {
    let text = ''
    if (typeof val === 'string') {
      text = val
    } else if (val instanceof Error) {
      text = val.message
    } else {
      text = JSON.stringify(val)
    }
    useNotificationStore().addNotification(text, 'error')
  },
}

