import type { loader as WebpackLoader } from 'webpack'
import { extractTags } from './tagExtractor'
import { matcher } from './scan'
import type { Component } from './types'

function install (this: WebpackLoader.LoaderContext, content: string, components: Component[]) {
  const imports = '{' + components.map(c => `${c.pascalName}: ${c.isAsync ? c.asyncImport : c.import}`).join(',') + '}'

  let newContent = '/* nuxt-component-imports */\n'
  newContent += `installComponents(component, ${imports})\n`

  // Insert our modification before the HMR code
  const hotReload = content.indexOf('/* hot reload */')
  if (hotReload > -1) {
    content = content.slice(0, hotReload) + newContent + '\n\n' + content.slice(hotReload)
  } else {
    content += '\n\n' + newContent
  }

  return content
}

export default async function loader (this: WebpackLoader.LoaderContext, content: string) {
  this.async()
  this.cacheable()

  if (!this.resourceQuery) {
    this.addDependency(this.resourcePath)

    const { getComponents } = this.query
    const nonAsyncComponents = getComponents().filter((c: Component) => c.isAsync !== true)

    const tags = await extractTags(this.resourcePath)
    const matchedComponents = matcher(tags, nonAsyncComponents)

    if (matchedComponents.length) {
      content = install.call(this, content, matchedComponents)
    }
  }

  this.callback(null, content)
}

import type { Ref } from 'vue'
import type { NuxtDevtoolsIframeClient } from '../types'
import { shallowRef, triggerRef } from 'vue'

let clientRef: Ref<NuxtDevtoolsIframeClient | undefined> | undefined
const hasSetup = false
const fns = [] as ((client: NuxtDevtoolsIframeClient) => void)[]

export function onDevtoolsClientConnected(fn: (client: NuxtDevtoolsIframeClient) => void) {
  fns.push(fn)

  if (hasSetup)
    return

  if (typeof window === 'undefined')
    return

  // eslint-disable-next-line ts/ban-ts-comment
  // @ts-ignore injection
  if (window.__NUXT_DEVTOOLS__) {
    // eslint-disable-next-line ts/ban-ts-comment
    // @ts-ignore injection
    fns.forEach(fn => fn(window.__NUXT_DEVTOOLS__))
  }

  Object.defineProperty(window, '__NUXT_DEVTOOLS__', {
    set(value) {
      if (value)
        fns.forEach(fn => fn(value))
    },
    get() {
      return clientRef!.value
    },
    configurable: true,
  })

  return () => {
    fns.splice(fns.indexOf(fn), 1)
  }
}

export function useDevtoolsClient() {
  if (!clientRef) {
    clientRef = shallowRef<NuxtDevtoolsIframeClient | undefined>()

    onDevtoolsClientConnected(setup)
  }

  function onUpdateReactivity() {
    if (clientRef) {
      triggerRef(clientRef)
    }
  }

  function setup(client: NuxtDevtoolsIframeClient) {
    clientRef!.value = client
    if (client.host)
      client.host.hooks.hook('host:update:reactivity', onUpdateReactivity)
  }

  return clientRef
}

import type { CodeHighlightOptions } from '@nuxt/devtools-kit/types'
import type { BundledLanguage, BundledTheme, Highlighter } from './shiki.bundle'
import { shallowRef } from 'vue'
import { bundledLanguages, bundledThemes, createHighlighter } from './shiki.bundle'

export const shiki = shallowRef<Highlighter>()

let promise: Promise<any> | null = null

export function renderCodeHighlight(
  code: string,
  lang: BundledLanguage | 'text' = 'text',
  options?: CodeHighlightOptions,
) {
  if (!promise && !shiki.value) {
    // Only loading when needed
    promise = createHighlighter({
      langs: Object.keys(bundledLanguages) as BundledLanguage[],
      themes: Object.keys(bundledThemes) as BundledTheme[],
    }).then((i) => {
      shiki.value = i
    })
  }

  const supported = shiki.value?.getLoadedLanguages().includes(lang)
  if (!supported) {
    return {
      code,
      supported,
    }
  }

  return {
    code: shiki.value!.codeToHtml(code, {
      ...options,
      lang,
      themes: {
        dark: 'vitesse-dark',
        light: 'vitesse-light',
      },
      transformers: [
        {
          root(hast) {
            return {
              type: 'root',
              // @ts-expect-error hast casting
              children: hast.children[0].children[0].children,
            }
          },
        },
      ],
    }),
    supported: true,
  }
}

import type { ConsolaReporter } from 'consola'

import process from 'node:process'

import { consola } from 'consola'

// Filter out unwanted logs
// TODO: Use better API from consola for intercepting logs
function wrapReporter(reporter: ConsolaReporter) {
  return ({
    log(logObj, ctx) {
      if (!logObj.args || !logObj.args.length) {
        return
      }
      const msg = logObj.args[0]
      if (typeof msg === 'string' && !process.env.DEBUG) {
        // Hide vue-router 404 warnings
        if (
          msg.startsWith(
            '[Vue Router warn]: No match found for location with path',
          )
        ) {
          return
        }
        // Suppress warning about native Node.js fetch
        if (
          msg.includes(
            'ExperimentalWarning: The Fetch API is an experimental feature',
          )
        ) {
          return
        }
        // TODO: resolve upstream in Vite
        // Hide sourcemap warnings related to node_modules
        if (msg.startsWith('Sourcemap') && msg.includes('node_modules')) {
          return
        }
      }
      return reporter.log(logObj, ctx)
    },
  }) satisfies ConsolaReporter
}

export function setupGlobalConsole(opts: { dev?: boolean } = {}) {
  consola.options.reporters = consola.options.reporters.map(wrapReporter)

  // Wrap all console logs with consola for better DX
  if (opts.dev) {
    consola.wrapAll()
  }
  else {
    consola.wrapConsole()
  }

  process.on('unhandledRejection', err =>
    consola.error('[unhandledRejection]', err))

  process.on('uncaughtException', err =>
    consola.error('[uncaughtException]', err))
}

import type { ModuleCustomTab, NuxtDevtoolsServerContext, ServerFunctions } from '../types'

export function setupCustomTabRPC({ nuxt, options, refresh }: NuxtDevtoolsServerContext) {
  const iframeTabs: ModuleCustomTab[] = []
  const customTabs: ModuleCustomTab[] = []

  // Add static custom tabs from the config
  if (options.customTabs?.length)
    customTabs.push(...options.customTabs)

  async function initHooks() {
    nuxt.hook('devtools:customTabs:refresh', initCustomTabs)
    await initCustomTabs()
  }

  async function initCustomTabs() {
    customTabs.length = 0
    if (options.customTabs?.length)
      customTabs.push(...options.customTabs)
    await nuxt.callHook('devtools:customTabs', customTabs)
    refresh('getCustomTabs')
  }

  nuxt.hook('app:resolve', async () => {
    await initHooks()
  })

  return {
    getCustomTabs() {
      return [
        ...iframeTabs,
        ...customTabs,
      ].map((i) => {
        i.category = i.category || 'modules'
        return i
      })
    },
    async customTabAction(name, actionIndex) {
      const tab = customTabs.find(i => i.name === name)
      if (!tab)
        return false
      const view = tab.view
      if (view.type !== 'launch')
        return false
      const action = view.actions?.[actionIndex]
      if (!action)
        return false

      Promise.resolve(action.handle?.())
        .catch((e) => {
          console.error(e)
        })
        .finally(() => {
          nuxt.callHook('devtools:customTabs:refresh')
        })
      nuxt.callHook('devtools:customTabs:refresh')
      return true
    },
  } satisfies Partial<ServerFunctions>
}

import type { NuxtDevToolsOptions, NuxtDevtoolsServerContext, ServerFunctions } from '../types'
import { defaultTabOptions } from '../constant'
import { clearLocalOptions, readLocalOptions, writeLocalOptions } from '../utils/local-options'

let options: NuxtDevToolsOptions | undefined

export function getOptions() {
  return options
}

export function setupOptionsRPC({ nuxt }: NuxtDevtoolsServerContext) {
  async function getOptions<T extends keyof NuxtDevToolsOptions>(tab: T): Promise<NuxtDevToolsOptions[T]> {
    if (!options || options[tab]) {
      options = defaultTabOptions
      await read(tab)
    }

    return options![tab]
  }

  async function read<T extends keyof NuxtDevToolsOptions>(tab: T) {
    options![tab] = await readLocalOptions<NuxtDevToolsOptions[T]>(defaultTabOptions[tab], {
      root: nuxt.options.rootDir,
      key: tab !== 'ui' && tab,
    })
    return options
  }

  getOptions('ui')

  async function clearOptions() {
    options = undefined
    await clearLocalOptions({
      root: nuxt.options.rootDir,
    })
  }

  return {
    async updateOptions(tab, _settings) {
      const settings = await getOptions(tab)
      Object.assign(settings, _settings)
      await writeLocalOptions(
        { ...settings },
        {
          root: nuxt.options.rootDir,
          key: tab !== 'ui' && tab,
        },
      )
      nuxt.callHook('builder:generateApp', {
        filter(template) {
          return template.filename.includes('devtools/settings.js')
        },
      })
    },
    getOptions,
    clearOptions,
  } satisfies Partial<ServerFunctions>
}

import type { NuxtHooks } from '@nuxt/schema'
import type { } from '@nuxt/telemetry'
import type { NuxtDevtoolsServerContext } from '../types'
import { version } from '../../package.json'
import { getOptions } from './options'

const SEND_DELAY = 5_000

type ArgumentsType<T> = T extends (...args: infer A) => any ? A : never

function throttle<T extends () => any>(fn: T, delay: number) {
  let timer: ReturnType<typeof setTimeout> | undefined

  return () => {
    if (!timer) {
      timer = setTimeout(() => {
        timer = undefined
        fn()
      }, delay)
    }
  }
}

let telemetry: ArgumentsType<NuxtHooks['telemetry:setup']>[0] | undefined

const throttledSend = throttle(() => {
  telemetry?.sendEvents()
}, SEND_DELAY)

export function setupTelemetryRPC({ nuxt, options }: NuxtDevtoolsServerContext) {
  if (options.telemetry !== false) {
    // Only when global telemetry is enabled, the hook will be called
    nuxt.hook('telemetry:setup', (t) => {
      telemetry = t
      // console.log('Telemetry is enabled')
      t.eventFactories.devtools = (_, payload) => {
        return {
          name: 'devtools',
          version,
          ...payload,
        }
      }
      t.createEvent('devtools', { event: 'enabled' })
    })
  }

  return {
    telemetryEvent(payload: object, immediate = false) {
      telemetryEvent(payload, immediate)
    },
  }
}

export function telemetryEvent(payload: object, immediate = false) {
  if (!telemetry)
    return

  if (getOptions()?.behavior.telemetry === false)
    return

  telemetry.createEvent('devtools', payload)

  if (immediate)
    telemetry.sendEvents()
  else
    throttledSend()
}

import type { HookInfo } from '@nuxt/devtools/types'
import type { Hookable } from 'hookable'

export function setupHooksDebug<T extends Hookable<any>>(hooks: T) {
  const serverHooks: Record<string, HookInfo> = {}

  // maybe run in node or browser env
  // performance api is not supported below node version v16.0.0
  // browser support https://caniuse.com/mdn-api_performance
  // if `performance` is undefined then downgrade to `Date`

  const now = typeof globalThis.performance === 'undefined'
    ? () => Date.now()
    : () => performance.now()

  hooks.beforeEach((event) => {
    if (!serverHooks[event.name]) {
      serverHooks[event.name] = {
        name: event.name,
        start: now(),
        // @ts-expect-error private field
        listeners: hooks._hooks[event.name]?.length || 0,
        executions: [],
      }
    }
    else {
      const hook = serverHooks[event.name]
      if (hook) {
        if (hook.duration != null)
          hook.executions.push(hook.duration)
        hook.start = now()
        hook.end = undefined
        hook.duration = undefined
      }
    }
  })

  hooks.afterEach((event) => {
    const hook = serverHooks[event.name]
    if (!hook)
      return
    hook.end = now()
    hook.duration = hook.end - hook.start
    // @ts-expect-error private field
    const listeners = hooks._hooks[event.name]?.length
    if (listeners != null)
      hook.listeners = listeners
  })
  return serverHooks
}

import { ref, watch, onBeforeMount, onBeforeUnmount } from 'vue'

export function useScrollspy() {
  const observer = ref<IntersectionObserver>()
  const visibleHeadings = ref<string[]>([])
  const activeHeadings = ref<string[]>([])

  function observerCallback(entries: IntersectionObserverEntry[]) {
    entries.forEach((entry) => {
      const id = entry.target.id
      if (!id) {
        return
      }

      if (entry.isIntersecting) {
        visibleHeadings.value = [...visibleHeadings.value, id]
      } else {
        visibleHeadings.value = visibleHeadings.value.filter(h => h !== id)
      }
    })
  }

  function updateHeadings(headings: Element[]) {
    headings.forEach((heading) => {
      if (!observer.value) {
        return
      }

      observer.value.observe(heading)
    })
  }

  watch(visibleHeadings, (val, oldVal) => {
    if (val.length === 0) {
      activeHeadings.value = oldVal
    } else {
      activeHeadings.value = val
    }
  })

  // Create intersection observer
  onBeforeMount(() => (observer.value = new IntersectionObserver(observerCallback)))

  // Destroy it
  onBeforeUnmount(() => observer.value?.disconnect())

  return {
    visibleHeadings,
    activeHeadings,
    updateHeadings
  }
}
